import sys
from collections import defaultdict

sys.setrecursionlimit(10**6)

class TarjanBridges:
    def __init__(self, n):
        self.n = n
        self.adj = defaultdict(list)
        self.disc = [-1] * n
        self.low = [-1] * n
        self.time = 0
        self.bridges = []

    def add_edge(self, u, v):
        self.adj[u].append(v)
        self.adj[v].append(u)

    def find_bridges(self):
        for i in range(self.n):
            if self.disc[i] == -1:
                self._dfs(i, -1)
        return self.bridges

    def _dfs(self, u, p):
        self.disc[u] = self.low[u] = self.time
        self.time += 1

        for v in self.adj[u]:
            if v == p:
                continue

            if self.disc[v] == -1:
                self._dfs(v, u)

                self.low[u] = min(self.low[u], self.low[v])

                if self.low[v] > self.disc[u]:
                    self.bridges.append(tuple(sorted((u, v))))
            else:
                self.low[u] = min(self.low[u], self.disc[v])

if __name__ == "__main__":
    n, m = map(int, sys.stdin.readline().split())

    tarjan = TarjanBridges(n)

    for _ in range(m):
        u, v = map(int, sys.stdin.readline().split())
        tarjan.add_edge(u, v)

    bridges = tarjan.find_bridges()

    bridges.sort() 

    for u, v in bridges:
        sys.stdout.write(f"{u} {v}\n")
